  function projects(){ const arr=window.data&&Array.isArray(window.data.projects)?window.data.projects:[]; return arr.length?arr:projectCache; }
  function pName(id){const p=projects().find(x=>String(x.id)===String(id));return p?.name||p?.project_name||'';}
  async function ensureProjectsLoaded(){
    if(projects().length || projectsLoaded) return projects();
    projectsLoaded=true;
    if(window.sb){
      const {data,error}=await window.sb.from('projects').select('id,name,project_name,status,supervisor_id').order('name',{ascending:true}).limit(1000);
      if(!error && data) projectCache=data;
    }
    return projects();
  }
  function normTxtV294(v){return String(v||'').toLowerCase().replace(/[\u064B-\u0652]/g,'').replace(/[أإآ]/g,'ا').replace(/ة/g,'ه').replace(/ى/g,'ي').replace(/\s+/g,' ').trim();}
  function compactTxtV296(v){return normTxtV294(v).replace(/[\s\-_،,./\\]+/g,'');}
  function sameProjectV296(a,b){ const A=normTxtV294(a), B=normTxtV294(b), CA=compactTxtV296(a), CB=compactTxtV296(b); if(!A||!B)return false; return A===B || CA===CB || A.includes(B) || B.includes(A) || CA.includes(CB) || CB.includes(CA); }
  function rowProjectNameV296(o,ex){ ex=ex||o?.extra_data||{}; return o?.project_name||ex.project_name||ex.project_filter_name||pName(o?.project_id)||''; }
  function projectNamesFromOrdersV294(){
    const names=[];
    try{ rowsBase().concat(legacyRows()).forEach(r=>{ if(r.project) names.push(String(r.project).trim()); }); }catch(e){}
    projects().forEach(p=>{ const nm=p.name||p.project_name; if(nm) names.push(String(nm).trim()); });
    return [...new Set(names.filter(Boolean))].sort((a,b)=>a.localeCompare(b,'ar'));
  }
  async function fillProjects(){
    await ensureProjectsLoaded();
    const opts=projects().map(p=>`<option value="${esc(p.id)}">${esc(p.name||p.project_name||p.id)}</option>`).join('');
    const formEl=$('o_project');
    if(formEl){ const current=formEl.value; formEl.innerHTML=`<option value="">اختر المشروع</option>`+opts; if(current) formEl.value=current; }
    const filterEl=$('filterProjectV290');
    if(filterEl){
      const current=filterEl.value;
      const nameOpts=projectNamesFromOrdersV294().map(n=>`<option value="name::${esc(n)}">${esc(n)}</option>`).join('');
      filterEl.innerHTML=`<option value="">كل المشاريع</option>`+nameOpts;
      if(current){ filterEl.value=current; if(filterEl.value!==current){
        const wanted=current.replace(/^name::/,'');
        const found=[...filterEl.options].find(o=>normTxtV294(o.textContent)===normTxtV294(wanted));
        if(found) filterEl.value=found.value;
      }}
    }
  }

