  function orderToRow(o){ const ex=o.extra_data||{}; const gross=n(o.approved_amount||o.estimated_amount||ex.gross_amount); const cost=n(o.cost_amount||ex.cost_amount); const c=calcGross(gross,cost); return {id:o.id,no:o.order_no,group:o.group_no,date:ex.order_date||String(o.created_at||'').slice(0,10),sender:o.requester_name,project:rowProjectNameV296(o,ex),property:ex.property_type,unit:ex.unit_no,client:ex.client_name,phone:ex.client_phone,executor:o.assigned_to,details:o.description||o.title,notes:o.finance_notes||ex.notes,belongs:ex.belongs_to,gross,vat:n(o.tax_amount||ex.tax_amount||c.vat),before:n(o.price_before_tax||ex.price_before_tax||c.before),cost,profit:n(o.profit_amount||ex.profit_amount||c.profit),payment:o.billing_status||ex.payment_status||'لم يحدد',invoice:o.invoice_no,billing:ex.system_billing_status,execStatus:ex.execution_status||'لم ينفذ',execDate:ex.execution_date,execMethod:o.execution_notes||ex.execution_method,report:ex.report_status||'لم يصدر',status:o.status,raw:o}; }
