  function updateKpis(rows){ const set=(id,v)=>{if($(id))$(id).textContent=v}; const total=rows.reduce((s,r)=>({gross:s.gross+n(r.gross),before:s.before+n(r.before),vat:s.vat+n(r.vat),cost:s.cost+n(r.cost),profit:s.profit+n(r.profit)}),{gross:0,before:0,vat:0,cost:0,profit:0}); set('kpiOrdersV290',rows.length); set('kpiGrossV290',money(total.gross)); set('kpiBeforeV290',money(total.before)); set('kpiVatV290',money(total.vat)); set('kpiCostV290',money(total.cost)); set('kpiProfitV290',money(total.profit)); set('kpiPaidV290',rows.filter(r=>r.payment==='تم السداد').length); ['create','finance','manager','all','legacy'].forEach(k=>{const e=$('count_'+k+'_v290'); if(e){let c=0; if(k==='finance')c=cache.filter(o=>o.status==='sent_finance').length; else if(k==='manager')c=cache.filter(o=>o.status==='finance_approved').length; else if(k==='legacy')c=legacyRows().length; else if(k==='all')c=cache.length+legacyRows().length; else c=canAdmin()?cache.filter(o=>o.status==='sent_finance').length:cache.filter(o=>String(o.requester_id||'')===String(uid()||'')).length; e.textContent='('+c+')';}}); document.querySelectorAll('.orders-tabs-v290 button').forEach(b=>b.classList.remove('active')); const tab=$('tab_'+active+'_v290'); if(tab)tab.classList.add('active'); }
